import React from 'react';
import logo from '../assets/KRAI.png'; // ✅ correct import path

function Header() {
  return (
    <header className="flex items-center justify-between px-6 py-4 bg-gradient-to-r from-purple-700 via-indigo-700 to-purple-900 shadow-lg">
      {/* ✅ Left side: Logo */}
      <img src={logo} alt="Logo" className="h-10 w-auto" />

      {/* ✅ Center: Title and subtitle */}
      <div className="text-center flex-1">
        <h1 className="text-3xl font-bold text-white">MeetingBot</h1>
        <p className="text-gray-300 mt-1 text-sm">AI-Powered Audio & Text File Transcription with Summarization</p>
      </div>
    </header>
  );
}

export default Header;
